import { G, T, A, O, P } from './domains.js';

export const part1 = [
  {id:1,domain:G,question:"Which cryptographic algorithm is asymmetric?",options:["RSA","AES","Blowfish","3DES"],answer:0,explanation:"RSA uses a public/private key pair (asymmetric). The others are all symmetric.",optionExplanations:["RSA is asymmetric, using a public key to encrypt and a private key to decrypt.","AES is a symmetric block cipher using the same key to encrypt and decrypt.","Blowfish is a symmetric block cipher, not asymmetric.","3DES is a symmetric cipher applying DES three times with one to three keys."]},
  {id:2,domain:G,question:"What does AAA stand for in network security?",options:["Authentication, Authorization, Accounting","Authentication, Access, Accountability","Access, Authentication, Auditing","Authorization, Accounting, Auditing"],answer:0,explanation:"AAA = Authentication (verify identity), Authorization (grant access), Accounting (track activity).",optionExplanations:["Correct. AAA covers verifying who you are, what you can do, and logging what you did.","Incorrect. 'Accountability' is a related concept but not the third A in AAA.","Incorrect. 'Access' and 'Auditing' are not the standard AAA terms.","Incorrect. The first A in AAA is Authentication, not Authorization."]},
  {id:3,domain:G,question:"Which principle limits users to only the permissions required for their job?",options:["Job rotation","Separation of duties","Least privilege","Need to know"],answer:2,explanation:"Least privilege restricts access to the minimum needed, reducing attack surface.",optionExplanations:["Job rotation moves employees through roles periodically to detect fraud, not to limit permissions.","Separation of duties requires multiple people to complete a sensitive task, not about limiting individual permissions.","Least privilege grants only the minimum access rights necessary to perform job functions.","Need to know is an information-access concept but not the term for minimum permission assignment."]},
  {id:4,domain:G,question:"Which hashing algorithm produces a 256-bit digest?",options:["SHA-512","SHA-1","MD5","SHA-256"],answer:3,explanation:"SHA-256 produces a 256-bit hash. MD5=128-bit, SHA-1=160-bit, SHA-512=512-bit.",optionExplanations:["SHA-512 produces a 512-bit digest, twice the size of SHA-256.","SHA-1 produces a 160-bit digest and is deprecated for most uses.","MD5 produces a 128-bit digest and is considered cryptographically broken.","SHA-256 is a member of the SHA-2 family and produces exactly a 256-bit output."]},
  {id:5,domain:G,question:"What is the primary purpose of a digital certificate?",options:["Provide a tamper-resistant hardware vault for securely generating and storing private key material","Bind a public key to an identity","Apply symmetric encryption to data stored on disk to protect it from unauthorized physical access","Enable two communicating parties to independently derive a shared secret key over an untrusted channel"],answer:1,explanation:"A digital certificate binds a public key to an identity, verified by a CA.",optionExplanations:["Tamper-resistant vaults for generating and storing private key material describe hardware security modules (HSMs).","A digital certificate cryptographically binds a public key to an entity's verified identity.","Applying symmetric encryption to data at rest describes full-disk or file encryption; that is not the purpose of a digital certificate.","Enabling parties to derive a shared secret key over an untrusted channel describes a Diffie-Hellman key exchange protocol."]},
  {id:6,domain:G,question:"Which protocol provides secure remote command-line access?",options:["Telnet","SSH","FTP","RDP"],answer:1,explanation:"SSH (port 22) encrypts remote shell sessions. Telnet and FTP are unencrypted.",optionExplanations:["Telnet transmits data including credentials in plaintext, making it insecure.","SSH encrypts the entire session including authentication, providing secure remote CLI access.","FTP transfers files but does not provide command-line access and sends data unencrypted.","RDP provides graphical remote desktop access on Windows, not a command-line protocol."]},
  {id:7,domain:G,question:"A user must present a password AND a fingerprint to log in. This is an example of:",options:["Role-based access control","Federated identity","Two-factor authentication","Single-factor authentication"],answer:2,explanation:"Using two different factor types (something you know + something you are) = MFA/2FA.",optionExplanations:["RBAC assigns permissions based on roles, not an authentication mechanism.","Federated identity allows authentication across organizational boundaries using a shared identity provider.","Two-factor authentication combines two distinct categories of factors; here, knowledge (password) and biometric (fingerprint).","Single-factor authentication requires only one form of verification, such as a password alone."]},
  {id:8,domain:G,question:"Which type of security control is an antivirus program?",options:["Detective","Corrective","Preventive","Deterrent"],answer:2,explanation:"Antivirus prevents malware from executing, so it is primarily a preventive control.",optionExplanations:["Detective controls identify threats after the fact, like IDS alerts or log reviews.","Corrective controls restore systems after an incident, like restoring from a backup.","Antivirus software prevents malware from running by blocking known malicious code before execution.","Deterrent controls discourage attacks through warnings or visible security presence."]},
  {id:9,domain:G,question:"What does PKI stand for?",options:["Public Key Infrastructure","Private Key Integration","Public Knowledge Interface","Protected Key Index"],answer:0,explanation:"PKI = Public Key Infrastructure — the framework of CAs, certificates, and policies for managing public keys.",optionExplanations:["Public Key Infrastructure is the correct expansion; it manages digital certificates and public key encryption.","Private Key Integration is not a real term in cryptography.","Public Knowledge Interface is not a recognized security acronym.","Protected Key Index is not an established security framework."]},
  {id:10,domain:G,question:"Which of the following best describes a Certificate Authority (CA)?",options:["A trusted entity that issues digital certificates","A protocol for key exchange","A server that stores encrypted passwords","A firewall that filters encrypted traffic"],answer:0,explanation:"A CA is a trusted third party that signs and issues digital certificates.",optionExplanations:["A CA is the correct answer; it verifies identities and signs certificates with its own private key.","Key exchange is handled by protocols like Diffie-Hellman or ECDH, not a CA.","Password storage is handled by identity providers or directory services, not a CA.","Firewalls filter network traffic by port, protocol, or application, not certificates."]},
  {id:11,domain:G,question:"Which of the following is an example of 'something you have' in MFA?",options:["Smart card","Fingerprint","Security question","Password"],answer:0,explanation:"'Something you have' is a physical token or device, like a smart card or hardware key.",optionExplanations:["A smart card is a physical possession factor — something you carry with you.","A fingerprint is 'something you are,' the inherence/biometric factor.","A security question is 'something you know,' not a possession factor.","A password is 'something you know,' the knowledge factor."]},
  {id:12,domain:G,question:"What is the purpose of a salt in password hashing?",options:["Prevent rainbow table attacks","Replace the need for hashing","Encrypt the password database","Speed up the hashing process"],answer:0,explanation:"A salt is random data added before hashing; it makes precomputed rainbow table attacks infeasible.",optionExplanations:["A unique random salt per password means identical passwords produce different hashes, defeating rainbow tables.","Salting works alongside hashing — it does not replace it.","Salting augments hashing but does not encrypt the database; encryption is a separate control.","Salting actually adds slight overhead; it does not speed up hashing."]},
  {id:13,domain:G,question:"Which access control model uses sensitivity labels and clearances?",options:["Attribute-Based Access Control (ABAC)","Mandatory Access Control (MAC)","Discretionary Access Control (DAC)","Role-Based Access Control (RBAC)"],answer:1,explanation:"MAC uses sensitivity labels (e.g., Top Secret) matched against user clearances, enforced by the OS.",optionExplanations:["ABAC evaluates attributes of users, resources, and environment dynamically, not fixed clearance levels.","MAC enforces access based on government-style classification labels and user clearance levels.","DAC lets resource owners set permissions; it does not use sensitivity labels or clearances.","RBAC assigns permissions to roles that users are placed in, not using classification labels."]},
  {id:14,domain:G,question:"What is the difference between symmetric and asymmetric encryption?",options:["Asymmetric encryption is the preferred choice for encrypting large volumes of bulk data efficiently","Symmetric uses one shared key; asymmetric uses a key pair","Symmetric encryption uses two mathematically related keys — one for encryption and a different one for decryption","Symmetric encryption is slower and less efficient than asymmetric encryption for all data sizes"],answer:1,explanation:"Symmetric: one shared secret key. Asymmetric: public/private key pair. Symmetric is faster for bulk data.",optionExplanations:["Asymmetric is too computationally slow for bulk data; symmetric algorithms like AES are used for encrypting large datasets.","Symmetric encryption uses one shared secret while asymmetric uses a mathematically related public/private key pair.","Symmetric encryption uses a single shared key for both encryption and decryption; it is asymmetric that uses two mathematically related keys.","Symmetric encryption is actually much faster than asymmetric, which is why TLS uses asymmetric cryptography only for key exchange."]},
  {id:15,domain:G,question:"Which protocol is used to authenticate users to a network using tickets?",options:["LDAP","TACACS+","RADIUS","Kerberos"],answer:3,explanation:"Kerberos uses a Key Distribution Center (KDC) to issue tickets for network authentication.",optionExplanations:["LDAP is a directory access protocol for querying user information, not an authentication ticket system.","TACACS+ is a Cisco protocol that separates authentication, authorization, and accounting but does not use tickets.","RADIUS provides centralized authentication for remote access but does not use tickets.","Kerberos issues Ticket Granting Tickets (TGT) and service tickets via the KDC."]},
  {id:16,domain:G,question:"A security team implements a policy requiring two employees to authorize financial transfers. This is an example of:",options:["Separation of duties","Least privilege","Need to know","Mandatory vacation"],answer:0,explanation:"Separation of duties splits critical tasks between two or more people to prevent fraud.",optionExplanations:["Separation of duties prevents any single individual from performing a complete sensitive transaction alone.","Least privilege limits individual permissions; it does not require multiple people for one task.","Need to know restricts access to information based on job requirements, not transaction approval.","Mandatory vacation forces employees to take leave so irregularities can be detected, a different control."]},
  {id:17,domain:G,question:"Which of the following is a stream cipher?",options:["Blowfish","RC4","3DES","AES"],answer:1,explanation:"RC4 is a stream cipher. AES, 3DES, and Blowfish are all block ciphers.",optionExplanations:["Blowfish is a block cipher with a variable key length, not a stream cipher.","RC4 is a widely known stream cipher that encrypts one bit or byte at a time.","3DES is a block cipher based on the original DES block cipher.","AES is a block cipher operating on 128-bit blocks, not a stream cipher."]},
  {id:18,domain:G,question:"What term describes the concept that data should only be modified by authorized parties?",options:["Non-repudiation","Confidentiality","Availability","Integrity"],answer:3,explanation:"Integrity ensures data is accurate and has not been tampered with by unauthorized parties.",optionExplanations:["Non-repudiation provides proof of origin, ensuring a sender cannot deny sending a message.","Confidentiality ensures data is not disclosed to unauthorized parties, not about modification.","Availability ensures systems and data are accessible when needed.","Integrity means data remains accurate, consistent, and unaltered except by authorized processes."]},
  {id:19,domain:G,question:"Which key exchange algorithm allows two parties to establish a shared secret over an insecure channel?",options:["SHA-256","RSA","AES","Diffie-Hellman"],answer:3,explanation:"Diffie-Hellman enables two parties to derive the same shared secret without transmitting it directly.",optionExplanations:["SHA-256 is a hash function, not a key exchange algorithm.","RSA can exchange keys but does so by encrypting the key with a public key, not deriving it jointly.","AES is a symmetric encryption algorithm, not a key exchange mechanism.","Diffie-Hellman allows two parties to independently compute the same shared secret over a public channel."]},
  {id:20,domain:G,question:"What type of certificate is used to secure multiple subdomains under a single domain?",options:["Root certificate","Self-signed certificate","Wildcard certificate","Code signing certificate"],answer:2,explanation:"A wildcard certificate (*.example.com) covers all immediate subdomains of a domain.",optionExplanations:["A root certificate belongs to a CA and signs subordinate certificates; it is not for securing subdomains.","Self-signed certificates are signed by their own private key and not trusted by default by browsers.","A wildcard certificate uses an asterisk (*) as the subdomain placeholder to cover all immediate subdomains.","Code signing certificates verify the identity of software publishers, not websites or subdomains."]},
  {id:21,domain:G,question:"Which of the following best describes non-repudiation?",options:["Ensuring systems and services remain continuously accessible through redundancy and fault tolerance","Preventing a sender from denying they sent a message","Requiring two distinct factor categories at login to significantly reduce the risk of account takeover","Applying TLS encryption to data as it travels between a client and server to prevent interception"],answer:1,explanation:"Non-repudiation provides cryptographic proof of origin so a sender cannot deny an action.",optionExplanations:["Ensuring services remain accessible through redundancy addresses availability, not proof of message origin.","Non-repudiation uses digital signatures to prove a specific party performed an action.","Requiring two factor categories at login is multi-factor authentication; it verifies identity but does not prevent denial of past actions.","Applying TLS encryption to data in transit provides confidentiality; it does not prove who sent the message."]},
  {id:22,domain:G,question:"A company stores passwords using bcrypt. What advantage does bcrypt offer over MD5?",options:["Bcrypt produces significantly shorter hash outputs than MD5, reducing storage requirements in authentication databases","Bcrypt functions as a symmetric block cipher that encrypts passwords using a secret key rather than hashing them","Bcrypt eliminates the need for salting because its algorithm intrinsically prevents rainbow table attacks","Bcrypt is intentionally slow and includes a work factor"],answer:3,explanation:"Bcrypt is designed to be computationally expensive; its work factor can be increased over time to resist brute force.",optionExplanations:["Bcrypt produces longer outputs than MD5's 128-bit digest; brevity is not its advantage — computational cost is.","Bcrypt is a password hashing function, not a symmetric encryption cipher; it is a one-way operation.","Bcrypt automatically generates and embeds a unique random salt per hash — it does not eliminate the need for salting.","The work factor makes bcrypt slow to compute, significantly raising the cost of brute-force attacks."]},
  {id:23,domain:G,question:"Which protocol does 802.1X use for authentication?",options:["Kerberos","TACACS+","RADIUS","LDAP"],answer:2,explanation:"802.1X is a port-based NAC standard that typically uses RADIUS as the backend authentication server.",optionExplanations:["Kerberos issues tickets within a domain but is not the authentication backend for 802.1X.","TACACS+ is used primarily in device administration (routers/switches) not typically as a 802.1X backend.","RADIUS is the standard backend authentication server used with 802.1X for network access control.","LDAP is a directory protocol for looking up user information, not the 802.1X authentication backend."]},
  {id:24,domain:G,question:"What type of control is a security guard at a data center entrance?",options:["Physical","Administrative","Compensating","Technical"],answer:0,explanation:"A security guard is a physical control — a human presence to control physical access.",optionExplanations:["A security guard is a physical control that directly protects physical access to a facility.","Administrative controls are policies, procedures, and training documents.","Compensating controls substitute for a primary control when it cannot be implemented.","Technical controls are implemented via technology such as firewalls, IDS, or encryption."]},
  {id:25,domain:G,question:"Which of the following is an example of a compensating control?",options:["A mandatory annual program that teaches employees to recognize phishing and practice safe security habits","Deploying MFA because password-only policies are insufficient","Full-disk encryption applied to laptop drives to protect sensitive data if a device is physically stolen","A firewall rule that explicitly denies inbound HTTP traffic on port 80 to reduce web server exposure"],answer:1,explanation:"A compensating control substitutes for a required control that cannot be fully implemented.",optionExplanations:["A mandatory phishing-awareness training program is an administrative preventive control, not a compensating control.","MFA deployed because single-factor authentication is too risky is a compensating control substituting for a stronger authentication requirement.","Full-disk encryption applied to laptops is a primary preventive technical control, not a substitute for another control.","A firewall rule explicitly denying port 80 traffic is a primary preventive technical control, not a substitute for another control."]},
  {id:26,domain:G,question:"Which encryption mode turns a block cipher into a stream cipher?",options:["CBC","GCM","ECB","CTR"],answer:3,explanation:"Counter (CTR) mode uses an incrementing counter to generate a keystream, converting a block cipher to stream-like operation.",optionExplanations:["CBC (Cipher Block Chaining) XORs each block with the previous ciphertext; it is still block-by-block.","GCM (Galois/Counter Mode) adds authentication to CTR mode but is also based on counter mode.","ECB (Electronic Codebook) encrypts each block independently, revealing patterns in plaintext.","CTR mode generates a keystream from a counter value, making the block cipher behave like a stream cipher."]},
  {id:27,domain:G,question:"What is the purpose of a hardware security module (HSM)?",options:["Perform real-time scanning of endpoint file systems to detect and quarantine malicious software","Monitor network traffic flows and generate alerts when patterns match known attack signatures","Securely generate, store, and manage cryptographic keys","Verify remote user identities using RADIUS authentication before allowing VPN tunnel establishment"],answer:2,explanation:"An HSM is a dedicated physical device for cryptographic key management and operations.",optionExplanations:["Real-time scanning of endpoints to detect malware describes EDR and antivirus solutions.","Monitoring network traffic for attack signatures describes an intrusion detection or prevention system, not an HSM.","HSMs are tamper-resistant devices specifically designed for secure key generation, storage, and cryptographic processing.","Verifying remote users via RADIUS before VPN access describes a network access control or AAA architecture."]},
  {id:28,domain:G,question:"Which protocol secures email in transit between mail servers?",options:["STARTTLS","S/MIME","PGP","DMARC"],answer:0,explanation:"STARTTLS upgrades a plain SMTP connection to TLS encryption between mail servers.",optionExplanations:["STARTTLS is used by SMTP servers to negotiate TLS encryption for messages in transit.","S/MIME encrypts and signs individual email messages end-to-end but does not secure server-to-server transport.","PGP encrypts message content end-to-end between users but not the transport layer between servers.","DMARC is an email authentication policy to prevent spoofing; it does not encrypt traffic."]},
  {id:29,domain:G,question:"What is the function of OCSP?",options:["Distribute CA-signed public key certificates to requesting entities through a directory query interface","Check whether a digital certificate has been revoked","Apply end-to-end encryption and digital signing to email messages so only the intended recipient can read them","Generate time-based one-time passwords using a shared secret and the current Unix timestamp for step-up authentication"],answer:1,explanation:"OCSP (Online Certificate Status Protocol) allows clients to check in real time if a certificate is revoked.",optionExplanations:["Distributing CA-signed certificates through a directory query interface describes LDAP-based certificate distribution.","OCSP enables real-time certificate revocation checking instead of downloading large, periodically-published CRLs.","Applying end-to-end encryption and digital signing to email messages describes S/MIME or PGP.","Generating time-based one-time passwords using a shared secret and timestamp describes TOTP (RFC 6238), not OCSP."]},
  {id:30,domain:G,question:"Which of the following describes role-based access control (RBAC)?",options:["Access based on user attributes and environment","Access based on data classification labels","Access based on job function","Access decisions made by the resource owner"],answer:2,explanation:"RBAC assigns permissions to roles (e.g., Manager, Admin), and users are placed in roles.",optionExplanations:["Attribute-based decisions describe Attribute-Based Access Control (ABAC).","Access based on classification labels describes Mandatory Access Control (MAC).","RBAC grants permissions to roles aligned with job functions, making administration scalable.","Resource owner-controlled access describes Discretionary Access Control (DAC)."]},
  {id:31,domain:G,question:"Which wireless security protocol replaced WPA2 and added stronger encryption?",options:["WEP","WPA3","802.11ac","WPA"],answer:1,explanation:"WPA3 introduced SAE (Simultaneous Authentication of Equals) and stronger 192-bit encryption for enterprise.",optionExplanations:["WEP is the oldest and most insecure wireless security protocol, deprecated decades ago.","WPA3 is the current standard, adding SAE for better authentication and forward secrecy.","802.11ac is a Wi-Fi speed standard (now called Wi-Fi 5), not a security protocol.","WPA was a temporary fix for WEP's weaknesses and has since been superseded."]},
  {id:32,domain:G,question:"What does TLS provide that SSL does not?",options:["Port-based network access control that verifies device compliance before granting LAN connectivity","Stronger cipher suites and security fixes","End-to-end data encryption between client and server, which was absent from all versions of SSL","Certificate-based server authentication using a chain of trust from a trusted Certificate Authority"],answer:1,explanation:"TLS is the successor to SSL with improved cipher suites, fixed vulnerabilities, and deprecated weak algorithms.",optionExplanations:["Port-based NAC that verifies device compliance describes 802.1X, which is unrelated to TLS or SSL.","TLS includes stronger cipher suites, removed support for weak algorithms, and fixed SSL's known vulnerabilities.","Both TLS and SSL provide encryption; the concept of encrypted transport is not something TLS uniquely introduced.","Certificate-based server authentication using a trust chain exists in both SSL and TLS."]},
  {id:33,domain:G,question:"Which term describes a vulnerability that is unknown to the vendor and has no patch?",options:["Legacy vulnerability","Common vulnerability","Zero-day","Known exploit"],answer:2,explanation:"A zero-day vulnerability is unknown to the vendor; there is no patch available at the time of discovery.",optionExplanations:["Legacy vulnerabilities exist in outdated software that the vendor may no longer support.","A 'common vulnerability' is a vague term; known CVEs have been reported to the vendor.","A zero-day vulnerability is unknown to the vendor, so no patch exists at time of exploitation.","A known exploit means the attack method is documented, usually after a patch is available."]},
  {id:34,domain:G,question:"Which of the following BEST describes data integrity?",options:["Data is accurate and has not been improperly altered","Data is protected from interception during transmission by applying encryption between endpoints","Data is restricted so that only explicitly authorized users or systems are permitted to read or access it","Data and systems remain accessible to authorized users whenever they are legitimately needed"],answer:0,explanation:"Integrity = data has not been tampered with and remains accurate and consistent.",optionExplanations:["Integrity ensures data remains accurate, complete, and unmodified by unauthorized parties.","Protecting data from interception during transmission by applying encryption addresses confidentiality in transit.","Restricting data access to explicitly authorized users describes confidentiality, not integrity.","Ensuring data and systems remain accessible whenever legitimately needed describes availability."]},
  {id:35,domain:G,question:"A web application uses HTTPS. Which layer does TLS operate at?",options:["Data link layer","Network layer","Transport layer","Application layer"],answer:2,explanation:"TLS operates at the Transport layer (Layer 4) of the OSI model, encrypting the session.",optionExplanations:["The data link layer (Layer 2) handles MAC addressing and framing, not TLS.","The network layer (Layer 3) handles IP addressing and routing; TLS does not operate here.","TLS sits between the transport layer and application layer, typically classified at Layer 4-5.","The application layer (Layer 7) is where HTTP operates; TLS secures it from below."]},
  {id:36,domain:G,question:"Which authentication factor is a retina scan?",options:["Something you are","Something you have","Something you know","Somewhere you are"],answer:0,explanation:"Biometric factors like retina scans are 'something you are' — inherence factors.",optionExplanations:["A retina scan is a biometric identifier, classified as 'something you are.'","'Something you have' includes smart cards, tokens, and mobile devices.","'Something you know' includes passwords, PINs, and security questions.","'Somewhere you are' is a location factor such as GPS location or IP geolocation."]},
  {id:37,domain:G,question:"What is the purpose of key escrow?",options:["Allow a trusted third party to hold a copy of encryption keys","Apply a one-way hashing function to passwords and store the resulting digests in an authentication database","Publish CA-signed public key certificates to directory servers so authorized parties can retrieve them on demand","Use ephemeral Diffie-Hellman key exchange parameters to derive a fresh symmetric session key for each TLS connection"],answer:0,explanation:"Key escrow allows a trusted third party (e.g., law enforcement or recovery agent) to access encryption keys when needed.",optionExplanations:["Key escrow stores a copy of encryption keys with a trusted third party for recovery or legal access.","Applying a one-way hash to passwords and storing the digests describes password hashing; key escrow is for encryption keys.","Publishing CA-signed public key certificates to directory servers for retrieval describes PKI certificate distribution, not key escrow.","Using ephemeral Diffie-Hellman parameters to derive a fresh symmetric session key describes TLS key exchange, not key escrow."]},
  {id:38,domain:G,question:"Which of the following is true about elliptic curve cryptography (ECC)?",options:["ECC requires substantially larger key sizes than RSA to achieve an equivalent level of cryptographic security","ECC is a public-key algorithm used only for key exchange and cannot be applied to create digital signatures","ECC provides equivalent security to RSA with much smaller key sizes","ECC is a symmetric encryption algorithm that uses the same key for both encryption and decryption operations"],answer:2,explanation:"ECC provides the same security as RSA with significantly shorter keys, making it efficient for mobile and IoT.",optionExplanations:["ECC requires much smaller keys than RSA; a 256-bit ECC key offers roughly equivalent security to a 3072-bit RSA key.","ECC is widely used for both digital signatures (ECDSA) and key exchange (ECDH), not limited to one purpose.","ECC provides equivalent security to RSA at much smaller key sizes, reducing computation and bandwidth overhead.","ECC is an asymmetric (public-key) algorithm that uses mathematically related key pairs, not a single shared secret."]},
  {id:39,domain:G,question:"What type of attack specifically targets the weakest link in the security chain — humans?",options:["Zero-day attack","SQL injection","Buffer overflow","Social engineering"],answer:3,explanation:"Social engineering manipulates people rather than exploiting technical vulnerabilities.",optionExplanations:["Zero-day attacks exploit unknown software vulnerabilities, not human behavior.","SQL injection is a technical attack against databases through unvalidated input.","Buffer overflow exploits memory management flaws in software code.","Social engineering exploits human psychology — trust, fear, urgency — to gain access or information."]},
  {id:40,domain:G,question:"Which of the following is an administrative security control?",options:["Security policy","Firewall","Antivirus software","CCTV camera"],answer:0,explanation:"Administrative controls are policies, procedures, and guidelines — management-level controls.",optionExplanations:["A security policy is an administrative control that defines rules and expectations for behavior.","A firewall is a technical/logical control implemented through technology.","Antivirus software is a technical control deployed on endpoints.","CCTV is a physical control used for monitoring and recording."]},
  {id:41,domain:G,question:"What is perfect forward secrecy (PFS)?",options:["Each session uses a unique ephemeral key so past sessions stay secure if long-term keys are compromised","Archiving all session encryption keys in a hardware security module vault for potential future decryption needs","Reusing a single long-term symmetric key across all sessions to ensure cryptographic consistency for all connections","Encrypting each data payload with two different keys simultaneously to provide layered cryptographic protection"],answer:0,explanation:"PFS generates a new ephemeral key pair for each session, so compromising one key does not expose past sessions.",optionExplanations:["PFS uses ephemeral keys per session so that compromise of the long-term private key does not decrypt past sessions.","Archiving session keys in an HSM vault creates a centralized target; PFS prevents past session decryption by never storing session keys long-term.","Reusing a single long-term symmetric key across all sessions is the opposite of PFS and means one key compromise exposes all sessions.","Encrypting each payload with two keys simultaneously describes layered or double encryption, not perfect forward secrecy."]},
  {id:42,domain:G,question:"Which of the following is NOT a property of a secure hash function?",options:["Fixed-length output","Reversible","Deterministic output","Collision resistant"],answer:1,explanation:"Hashing is a one-way function; it cannot be reversed. This is a fundamental property.",optionExplanations:["Fixed-length output regardless of input size is a required hash function property.","Reversibility would make it an encryption function, not a hash; hashing must be one-way.","Deterministic output means the same input always produces the same hash — a required property.","Collision resistance means it should be computationally infeasible to find two inputs with the same hash."]},
  {id:43,domain:G,question:"A certificate is revoked before its expiration date. Which mechanism provides the most current revocation status?",options:["LDAP","CRL","DNS","OCSP"],answer:3,explanation:"OCSP provides real-time certificate revocation status, while CRLs can be large and cached.",optionExplanations:["LDAP is a directory protocol for user lookups, not certificate revocation status.","CRLs (Certificate Revocation Lists) are published periodically and may be stale by the time they are checked.","DNS is used for name resolution; DANE can link certs to DNS, but OCSP is the standard revocation check.","OCSP (Online Certificate Status Protocol) provides real-time, per-certificate revocation checking."]},
  {id:44,domain:G,question:"Which statement about symmetric encryption is correct?",options:["It is slower than asymmetric encryption","It uses separate keys for encryption and decryption","It is ideal for bulk data encryption","It provides built-in non-repudiation"],answer:2,explanation:"Symmetric encryption is fast and efficient, making it ideal for encrypting large amounts of data.",optionExplanations:["Symmetric encryption is faster than asymmetric encryption due to simpler mathematical operations.","Symmetric encryption uses the same key for both encryption and decryption.","Symmetric encryption is the correct choice for encrypting large data volumes because of its speed.","Non-repudiation requires asymmetric digital signatures; symmetric encryption does not provide it."]},
  {id:45,domain:G,question:"Which of the following describes steganography?",options:["Distributing data blocks across multiple storage devices simultaneously to improve redundancy and read performance","Hiding data within another file or medium","Transforming plaintext into unreadable ciphertext using a secret key so only authorized parties can read it","Cascading multiple independent encryption algorithms in sequence to provide layered cryptographic protection"],answer:1,explanation:"Steganography conceals the existence of data by hiding it within another file such as an image.",optionExplanations:["Distributing data blocks across multiple drives for redundancy describes RAID striping, not steganography.","Steganography hides secret data inside a carrier file (image, audio, video) to conceal its existence.","Transforming plaintext into ciphertext using a secret key describes symmetric cryptography, not steganography.","Cascading multiple encryption algorithms for layered protection describes cascaded or double encryption, not steganography."]},
  {id:46,domain:G,question:"What does SAML provide in federated identity management?",options:["Applying TLS encryption to password submissions as they travel between the user's browser and the identity provider","Enabling SSO by passing authentication assertions between identity and service providers","Managing the lifecycle of X.509 certificates including issuance, renewal, and revocation across the enterprise","Capturing fingerprint or retina biometric data at authentication time to verify the user's physical identity"],answer:1,explanation:"SAML (Security Assertion Markup Language) passes XML-based authentication assertions to enable SSO across organizations.",optionExplanations:["Applying TLS to password submissions in transit is handled by HTTPS at the transport layer, not SAML.","SAML passes authentication and authorization assertions between identity providers and service providers to enable SSO.","Managing X.509 certificate lifecycle including issuance and revocation is the function of a PKI, not SAML.","Capturing biometric data at authentication time is handled at the identity provider's authentication system; SAML only transports the resulting assertion."]},
  {id:47,domain:G,question:"Which of the following describes a man-in-the-middle (MITM) attack?",options:["An attacker systematically submits every possible password combination until successfully authenticating","An attacker writes data past the end of a fixed-size memory buffer to overwrite adjacent memory and execute code","An attacker intercepts and possibly alters communication between two parties","An attacker directs massive volumes of traffic from many compromised systems to overwhelm a target server"],answer:2,explanation:"MITM attacks intercept communication between two parties, potentially reading or altering the data.",optionExplanations:["Systematically submitting every possible password combination until one succeeds describes a brute force attack.","Writing data past a fixed-size buffer to overwrite memory and execute code describes a buffer overflow attack.","In a MITM attack, the attacker positions themselves between communicating parties to intercept or modify messages.","Directing massive volumes of traffic from many compromised systems to overwhelm a target describes a DDoS attack."]},
  {id:48,domain:G,question:"What is the primary purpose of a VPN?",options:["Absorb volumetric traffic floods by distributing incoming attack packets across distributed scrubbing centers","Verify the identity of remote users by validating X.509 certificates issued by an enterprise Certificate Authority","Perform continuous behavioral analysis of endpoint processes to detect and quarantine advanced malware","Create an encrypted tunnel over an untrusted network"],answer:3,explanation:"A VPN creates an encrypted tunnel so traffic traversing an untrusted network (like the Internet) remains private.",optionExplanations:["Absorbing traffic floods through distributed scrubbing centers describes DDoS mitigation services, not VPNs.","Verifying remote users via X.509 certificate validation can be one component of VPN authentication, but it is not the VPN's primary purpose.","Performing behavioral analysis of endpoint processes to detect advanced malware describes EDR (endpoint detection and response).","A VPN encapsulates and encrypts traffic so it remains confidential and integral over untrusted networks."]},
  {id:49,domain:G,question:"A developer uses HTTPS for a web app but the certificate is self-signed. What is the main risk?",options:["Users cannot verify the server's identity through a trusted CA","Browser session cookies are rejected by default when the server's certificate is not signed by a trusted CA","The TLS handshake overhead with a self-signed certificate is significantly higher, causing slower page load times","Traffic between the browser and the server will travel in plaintext because self-signed certificates cannot enable TLS"],answer:0,explanation:"Self-signed certificates encrypt traffic but are not trusted by browsers — users cannot verify the server's identity.",optionExplanations:["Without a CA signature, browsers cannot validate the certificate, leaving users unable to verify server identity.","Session cookies function correctly with self-signed certificates; cookie handling depends on secure attributes, not CA trust.","Certificate type does not significantly impact TLS handshake overhead or connection speed; the cryptographic operations are the same.","HTTPS still encrypts traffic even with a self-signed certificate; the encryption is functionally identical, only trust is missing."]},
  {id:50,domain:G,question:"Which of the following is the function of an IV (initialization vector) in encryption?",options:["Compute a keyed hash of the message to allow the recipient to verify that data has not been tampered with","Add randomness to the first block to prevent identical ciphertexts","Serve as a substitute for the encryption key to allow decryption without revealing the actual cryptographic secret","Provide a tamper-resistant storage location for the symmetric decryption key on the encrypting system"],answer:1,explanation:"An IV adds randomness so that identical plaintexts encrypted with the same key produce different ciphertexts.",optionExplanations:["Computing a keyed hash to verify message integrity describes a message authentication code (MAC) or HMAC, not an IV.","An IV ensures that encrypting the same plaintext multiple times with the same key yields different ciphertexts, preventing pattern analysis.","An IV is not a substitute for the encryption key; both are independent inputs to the cipher, each serving a different purpose.","Providing tamper-resistant storage for symmetric keys describes a hardware security module or key store, not an IV."]},
  {id:51,domain:G,question:"Which of the following BEST describes a digital signature?",options:["Encrypting the full message content with the recipient's public key so only they can read it with their private key","Allowing two parties to independently derive the same shared secret value over an insecure public channel","Generating a random symmetric key to encrypt session data after the asymmetric handshake completes","Encrypting a hash of the message with the sender's private key"],answer:3,explanation:"A digital signature = hash of message encrypted with sender's private key; recipient decrypts with sender's public key.",optionExplanations:["Encrypting message content with the recipient's public key provides confidentiality; it does not authenticate the sender's identity.","Allowing two parties to derive the same shared secret over a public channel describes Diffie-Hellman key exchange.","Generating a random symmetric key for session encryption after an asymmetric handshake describes session key establishment in TLS.","A digital signature encrypts the message digest (hash) with the sender's private key for authenticity and non-repudiation."]},
  {id:52,domain:G,question:"What is a CRL?",options:["A list of certificates that have been revoked before expiration","A time-stamped log maintained by authentication servers recording each failed login attempt for audit purposes","A repository storing pending certificate signing requests submitted by entities awaiting CA approval","A prioritized list of cryptographic algorithms a TLS server is configured to accept during cipher negotiation"],answer:0,explanation:"A Certificate Revocation List (CRL) is published by a CA listing certificates revoked before their expiry.",optionExplanations:["A CRL is a CA-maintained list of serial numbers of revoked certificates that should no longer be trusted.","A time-stamped log of failed login attempts is stored in SIEM or authentication server logs, not a CRL.","A repository storing pending certificate signing requests from entities awaiting approval describes a CA request queue, not a CRL.","A prioritized list of cryptographic algorithms a TLS server accepts describes a cipher suite configuration, not a CRL."]},
  {id:53,domain:G,question:"Which protocol provides centralized authentication, authorization, and accounting for network device administration?",options:["SAML","RADIUS","Kerberos","TACACS+"],answer:3,explanation:"TACACS+ separates authentication, authorization, and accounting and is commonly used for managing network devices.",optionExplanations:["SAML is an SSO/federation protocol for web applications, not network device administration.","RADIUS combines authentication and authorization in one step and is primarily used for network access, not device administration.","Kerberos uses tickets for domain authentication; it is not typically used for network device management.","TACACS+ keeps AAA functions separate and encrypts the entire payload, making it preferred for device administration."]},
  {id:54,domain:G,question:"What is the main difference between identification and authentication?",options:["They are the same process","Identification verifies; authentication claims","Identification claims identity; authentication verifies it","Authentication happens before identification"],answer:2,explanation:"Identification = claiming who you are (username); Authentication = proving it (password, biometric).",optionExplanations:["They are distinct steps: first you identify yourself, then prove it.","Identification claims identity; authentication verifies the claim — not the other way around.","Identification is claiming an identity (entering a username); authentication proves that claim (entering a password).","Authentication always follows identification; you must first claim an identity before proving it."]},
  {id:55,domain:G,question:"Which of the following is an example of a technical security control?",options:["Data encryption","Background checks","Acceptable use policy","Security awareness training"],answer:0,explanation:"Technical controls are implemented through technology: firewalls, encryption, IDS, access controls.",optionExplanations:["Data encryption is a technical control that protects data confidentiality using cryptography.","Background checks are administrative (personnel) controls.","An acceptable use policy is an administrative control.","Security awareness training is an administrative/preventive control."]},
  {id:56,domain:G,question:"Which of the following is TRUE about WPA3 Enterprise?",options:["It uses TKIP for encryption","It requires 192-bit encryption","It is backward compatible with WEP","It uses a pre-shared key for authentication"],answer:1,explanation:"WPA3 Enterprise mandates a 192-bit security suite for the highest protection level.",optionExplanations:["WPA3 uses GCMP-256 for encryption, replacing WPA2's CCMP/AES and the deprecated TKIP.","WPA3 Enterprise requires a 192-bit minimum security suite (CNSA suite) for government/sensitive environments.","WEP is a decades-old broken protocol; WPA3 has no compatibility with it.","Pre-shared keys are used in WPA3 Personal (SAE), not WPA3 Enterprise."]},
  {id:57,domain:G,question:"What does the term 'defense in depth' mean?",options:["Layering multiple security controls so failure of one does not compromise the system","Deploying one highly sophisticated security control and relying entirely on its strength to stop all attacks","Encrypting all data as it traverses each individual network segment between source and destination","Mandating thorough background investigation screening for every new employee before granting system access"],answer:0,explanation:"Defense in depth uses multiple overlapping security layers so an attacker must defeat several controls.",optionExplanations:["Defense in depth layers multiple controls (technical, administrative, physical) so no single control failure is catastrophic.","Relying on a single highly sophisticated control is the opposite of defense in depth and creates a single point of failure.","Encrypting data at each network segment hop is a data-in-transit strategy; defense in depth encompasses all control types and domains.","Background investigations are one administrative layer; defense in depth is the broader philosophy of layering many diverse controls."]},
  {id:58,domain:G,question:"Which port does HTTPS use by default?",options:["22","8080","80","443"],answer:3,explanation:"HTTPS (HTTP over TLS) runs on TCP port 443 by default.",optionExplanations:["Port 22 is reserved for SSH, not HTTPS.","Port 8080 is a common alternative HTTP port used for development/proxy purposes.","Port 80 is the default for unencrypted HTTP traffic.","Port 443 is the well-known port for HTTPS — HTTP secured with TLS."]},
  {id:59,domain:G,question:"Which of the following BEST describes role-based access control?",options:["Access is granted based on a combination of user, resource, and environmental attributes","The resource owner determines who can access their data","Access is determined by the system based on data labels","Users are granted access based on their job function and role"],answer:3,explanation:"In RBAC, permissions are assigned to roles (e.g., HR, Finance) and users inherit permissions by being assigned a role.",optionExplanations:["Multi-attribute decisions describe Attribute-Based Access Control (ABAC).","Owner-controlled access describes Discretionary Access Control (DAC).","Access determined by data labels describes Mandatory Access Control (MAC).","RBAC maps permissions to job roles, reducing administrative overhead and improving consistency."]},
  {id:60,domain:G,question:"Which of the following is a detective security control?",options:["A software solution that monitors data transfers and blocks unauthorized movement of sensitive files in real time","Applying cryptographic algorithms to sensitive data so that unauthorized access yields unreadable ciphertext","Security camera footage reviewed after an incident","Installing high-security physical locks on server room doors to prevent unauthorized personnel from gaining entry"],answer:2,explanation:"Detective controls identify incidents after they occur; reviewing camera footage to detect a breach is detective.",optionExplanations:["A solution that monitors and blocks unauthorized data movement in real time describes DLP — primarily a preventive control.","Applying cryptography to sensitive data to make it unreadable to unauthorized parties is a preventive control.","Reviewing security camera footage after an incident detects that an event occurred — a detective control.","Installing physical locks on server room doors to block unauthorized personnel entry is a preventive physical control."]},
  {id:61,domain:G,question:"What is the purpose of a nonce in cryptography?",options:["Derive the public component of an asymmetric key pair through mathematical operations on curve parameters","Serve as a long-term storage container for symmetric encryption keys within a key management system","Ensure a value is used only once to prevent replay attacks","Act as a direct substitute for the initialization vector in CBC and CTR mode encryption operations"],answer:2,explanation:"A nonce (number used once) prevents replay attacks by ensuring each request or session is unique.",optionExplanations:["Public keys are derived from mathematical operations on private key parameters; they are not generated from nonces.","A long-term container for symmetric encryption keys describes a key management system or HSM, not a nonce.","A nonce is used exactly once to guarantee freshness and prevent attackers from replaying captured messages.","An IV randomizes encryption; while nonces and IVs serve similar anti-replay roles, a nonce specifically ensures uniqueness in protocols."]},
  {id:62,domain:G,question:"What distinguishes TOTP from HOTP?",options:["TOTP exclusively requires a dedicated hardware token while HOTP can only be implemented as a software application","TOTP synchronizes on an incrementing event counter while HOTP uses the current Unix timestamp divided into 30-second windows","TOTP is based on time intervals; HOTP is based on a counter","TOTP and HOTP are functionally equivalent algorithms that produce identical codes under all conditions"],answer:2,explanation:"TOTP (Time-based OTP) rotates every 30 seconds. HOTP (HMAC-based OTP) increments a counter with each use.",optionExplanations:["Both TOTP and HOTP can be implemented in hardware tokens or software applications such as authenticator apps.","HOTP uses an event counter that increments with each authentication attempt; TOTP uses time — the descriptions are reversed here.","TOTP generates a new code every 30 seconds based on the current time; HOTP increments a shared counter with each use.","TOTP and HOTP differ fundamentally in their synchronization mechanism — time versus event counter — producing different codes."]},
  {id:63,domain:G,question:"A company implements biometric authentication. Which of the following is a major concern?",options:["Biometric authentication systems require constant cloud connectivity to validate templates and cannot function offline","Modern enterprise biometric readers are prohibitively slow, causing unacceptable delays in high-volume authentication workflows","Biometrics are incompatible with multi-factor authentication frameworks and cannot be combined with passwords or tokens","Biometric data cannot be changed if compromised"],answer:3,explanation:"Unlike passwords, biometric traits (fingerprints, retinas) cannot be reissued if the stored template is breached.",optionExplanations:["Biometric matching frequently occurs locally on-device using stored templates, functioning fully without any internet connectivity.","Modern biometric readers (fingerprint, facial recognition) are fast and widely deployed in enterprise environments without causing meaningful delays.","Biometrics are commonly and effectively used as an inherence factor in MFA alongside passwords or hardware tokens.","If biometric templates are stolen, the underlying trait cannot be changed, creating a permanent and irremediable vulnerability."]},
  {id:64,domain:G,question:"What does the term 'open authentication' (OAuth) primarily provide?",options:["Authorization delegation allowing a user to grant third-party access without sharing credentials","Applying end-to-end encryption to password fields so credentials cannot be intercepted during transmission","Requiring users to supply a second authentication factor such as a TOTP code before completing login","Managing the full lifecycle of X.509 certificates including issuance, renewal, and revocation"],answer:0,explanation:"OAuth allows a user to authorize a third-party app to access their resources without exposing their credentials.",optionExplanations:["OAuth issues scoped access tokens that grant limited access to user resources on behalf of the user, without sharing credentials.","Applying encryption to password fields describes TLS transport security; OAuth eliminates the need to transmit passwords to third parties.","Requiring a second authentication factor like a TOTP code describes multi-factor authentication, a separate mechanism from OAuth.","Managing the lifecycle of X.509 certificates describes a Public Key Infrastructure (PKI), not OAuth."]},
  {id:65,domain:G,question:"Which cipher mode provides both encryption and authentication?",options:["GCM","ECB","CTR","CBC"],answer:0,explanation:"GCM (Galois/Counter Mode) provides confidentiality (counter mode) and message authenticity (GHASH).",optionExplanations:["GCM combines CTR encryption with a GHASH authentication tag, providing both confidentiality and integrity.","ECB encrypts blocks independently with no authentication and reveals patterns — the weakest mode.","CTR mode provides encryption but not built-in authentication.","CBC provides encryption but requires a separate MAC for authentication."]},
  {id:66,domain:G,question:"What is a PKI trust anchor?",options:["The root CA whose certificate is inherently trusted","A subordinate CA certificate that chains to the root and is used to issue end-entity certificates","A tamper-resistant hardware device that securely stores and performs cryptographic operations with private keys","A leaf certificate issued directly to an end entity such as a web server, email user, or code-signing account"],answer:0,explanation:"The root CA is the trust anchor; its self-signed certificate is explicitly trusted in certificate stores.",optionExplanations:["The root CA is the ultimate trust anchor; its self-signed certificate is pre-installed in browsers and operating systems.","A subordinate (intermediate) CA certificate is signed by the root and inherits trust through the chain, but it is not itself the anchor.","A tamper-resistant hardware device storing private keys describes an HSM; it is not a trust anchor in the PKI chain of trust.","Leaf certificates issued to end entities like web servers chain upward through intermediates to the root; they are not the trust anchor."]},
  {id:67,domain:G,question:"Which of the following is a characteristic of attribute-based access control (ABAC)?",options:["Access permissions are determined by static data classification labels attached to each protected resource","Access permissions are granted according to a set of predefined organizational job roles assigned to each user account","Access decisions evaluate user, resource, and environmental attributes simultaneously","Access decisions rest solely with the resource's designated owner, who grants permissions at their own discretion"],answer:2,explanation:"ABAC evaluates multiple attributes dynamically — user department, resource sensitivity, time of day, location, etc.",optionExplanations:["This describes MAC, where access is governed by fixed classification labels rather than combined attribute evaluation.","This describes RBAC, where permissions are tied to predefined job roles rather than dynamic attribute evaluation.","ABAC is highly flexible, evaluating combinations of attributes about the user, resource, and environment simultaneously to make access decisions.","This describes DAC, where the resource owner grants access at their discretion rather than through attribute-based policy evaluation."]},
  {id:68,domain:G,question:"Which of the following protocols encrypts the ENTIRE RADIUS packet, including the username?",options:["TACACS+","LDAP over TLS","RADIUS over TCP","RADIUS over UDP"],answer:0,explanation:"TACACS+ encrypts the entire packet body. RADIUS only encrypts the password field.",optionExplanations:["TACACS+ encrypts the entire packet payload, providing better protection than standard RADIUS.","LDAP over TLS encrypts the LDAP session but is a directory protocol, not an AAA protocol.","RADIUS over TCP (RADIUS/TLS or RadSec) encrypts everything, but standard TACACS+ is the more common answer here.","Standard RADIUS over UDP encrypts only the password field, leaving the username in plaintext."]},
  {id:69,domain:G,question:"What is the purpose of a cross-certification between two PKIs?",options:["Automatically revoke certificates issued by either CA when a breach is detected, propagating the revocation across both hierarchies","Permanently merge two separate CA hierarchies by consolidating their root certificates into a single unified root CA","Allow users of one PKI to trust users of another PKI","Improve the speed of certificate status lookups by distributing OCSP responders across both PKI environments"],answer:2,explanation:"Cross-certification creates mutual trust between separate PKI hierarchies so entities in each can validate the other's certificates.",optionExplanations:["Revocation propagation across PKIs is handled through CRLs and OCSP within each PKI independently, not by cross-certification.","Merging two CA hierarchies into a single root would require re-issuing all certificates; cross-certification creates trust without merging.","Cross-certification establishes a bilateral trust relationship between two separate PKI environments so each trusts the other's certificates.","Certificate validation speed depends on OCSP/CRL infrastructure within each PKI; cross-certification is about trust establishment."]},
  {id:70,domain:G,question:"Which of the following describes a 'chain of trust' in PKI?",options:["The hierarchy from root CA through intermediate CAs to end-entity certificates","A series of encrypted communication tunnels established directly between two or more servers for data transport","A continuously updated linked list of certificates that have been revoked before their scheduled expiration date","A network protocol used to cryptographically verify the ownership of specific IP addresses on a network"],answer:0,explanation:"The chain of trust links an end-entity certificate back to a trusted root CA via intermediate CAs.",optionExplanations:["The certificate chain of trust goes from the end-entity certificate through intermediates to the root CA.","This describes encrypted tunnels such as VPNs or TLS sessions, not the certificate hierarchy of PKI.","This describes a certificate revocation list (CRL), which is a distinct PKI component from the chain of trust hierarchy.","IP address verification is handled by protocols like DNSSEC or BGP security, not by the PKI chain of trust."]},
  {id:71,domain:G,question:"Which of the following is a feature of SSO (Single Sign-On)?",options:["One set of credentials grants access to multiple systems","Each system maintains its own password database","SSO eliminates the need for encryption","Users must log in separately to each system"],answer:0,explanation:"SSO lets users authenticate once and gain access to all connected systems without re-authenticating.",optionExplanations:["SSO authenticates the user once, then passes tokens or assertions to other systems, eliminating repeated logins.","With SSO, a central identity provider manages authentication; individual systems rely on it.","SSO addresses authentication, not encryption; both can coexist independently.","Logging in separately to each system is the problem SSO solves."]},
  {id:72,domain:G,question:"What is the purpose of a security token in authentication?",options:["Apply full-disk encryption to protect sensitive files stored on a laptop or portable storage device from physical theft","Act as a complete replacement for fingerprint and retina biometric authentication factors in all enterprise scenarios","Inspect network packets for malicious signatures and block or alert on detected intrusion attempts","Generate or store one-time passwords or cryptographic keys for authentication"],answer:3,explanation:"Security tokens (hardware or software) generate OTPs or store private keys to prove identity.",optionExplanations:["Applying full-disk encryption to protect stored data describes a storage encryption tool, not a security token.","Security tokens supplement or replace passwords but do not necessarily replace all biometric factors in every scenario.","Inspecting network packets for malicious signatures and alerting on intrusions describes IDS/IPS and SIEM tools.","Security tokens produce time-based or counter-based OTPs, or store cryptographic material for strong authentication."]},
  {id:73,domain:G,question:"Which of the following BEST describes the concept of 'need to know'?",options:["Users should only access information required for their specific task","All users in a role share the same access level","Users should have the minimum permissions for their job","Administrators can override all access restrictions"],answer:0,explanation:"Need to know means even if you have clearance, you should only access information you specifically require for a task.",optionExplanations:["Need to know restricts information access to what is necessary for a particular task, even within authorized clearance.","Shared role-based access describes RBAC; need to know applies further granular restrictions within roles.","Minimum permissions for a job describes least privilege, a related but distinct concept.","Unrestricted admin override would violate both least privilege and need to know principles."]},
  {id:74,domain:G,question:"A company wants to ensure no single administrator can access a key alone. Which concept applies?",options:["Key escrow","Least privilege","Dual control","Separation of duties"],answer:2,explanation:"Dual control requires two authorized individuals to be present for a sensitive operation, like accessing a cryptographic key.",optionExplanations:["Key escrow holds keys with a trusted third party for recovery, not specifically about requiring two people.","Least privilege limits permissions but does not require two-person presence for access.","Dual control specifically requires two people simultaneously to perform a sensitive operation.","Separation of duties splits different parts of a task among people, but dual control specifically requires simultaneous presence."]},
  {id:75,domain:G,question:"Which of the following is NOT a goal of information security?",options:["Confidentiality","Availability","Integrity","Profitability"],answer:3,explanation:"The CIA triad covers Confidentiality, Integrity, and Availability. Profitability is a business goal, not an information security goal.",optionExplanations:["Confidentiality is the C in the CIA triad, a core information security goal.","Availability is the A in the CIA triad, ensuring systems are accessible when needed.","Integrity is the I in the CIA triad, ensuring data accuracy and trustworthiness.","Profitability is a business objective, not an information security goal."]},
  {id:76,domain:T,question:"Which type of malware disguises itself as legitimate software?",options:["Ransomware","Worm","Trojan","Virus"],answer:2,explanation:"A Trojan masquerades as legitimate software to trick users into installing it.",optionExplanations:["Ransomware encrypts data and demands payment; while a Trojan can deliver ransomware, ransomware itself is a category.","A worm self-replicates across networks without needing to be attached to a host program.","A Trojan appears to be useful software but carries malicious payload; it does not self-replicate.","A virus attaches to a host file and replicates when the file is executed."]},
  {id:77,domain:T,question:"What is a rootkit?",options:["Malware that encrypts victim files and demands cryptocurrency payment in exchange for the decryption key","Self-replicating malware that propagates automatically through email attachments and shared network drives","Software that hides its presence and provides privileged access to an attacker","A port-scanning utility that maps open services on target systems to identify attack vectors"],answer:2,explanation:"Rootkits hide malicious code and provide persistent privileged access while evading detection.",optionExplanations:["File-encrypting malware demanding payment describes ransomware, which operates very differently from a rootkit's stealth and persistence goals.","Self-replicating malware spreading via email describes a worm; worms do not primarily focus on hiding themselves from detection.","A rootkit embeds itself at the OS or kernel level to conceal itself and give attackers persistent privileged access.","Port-scanning utilities are reconnaissance tools used before an attack; rootkits are post-compromise persistence and stealth mechanisms."]},
  {id:78,domain:T,question:"Which attack targets the DNS system to redirect users to malicious websites?",options:["Session hijacking","DNS poisoning","Phishing","ARP spoofing"],answer:1,explanation:"DNS poisoning (cache poisoning) injects malicious records into a DNS cache, redirecting users to attacker-controlled sites.",optionExplanations:["Session hijacking steals an authenticated session token to impersonate a logged-in user.","DNS poisoning corrupts DNS cache entries so hostnames resolve to attacker IP addresses.","Phishing sends deceptive messages to trick users into revealing credentials; it does not modify DNS.","ARP spoofing maps an attacker's MAC to a legitimate IP address on a local network, a LAN-layer attack."]},
  {id:79,domain:T,question:"A user receives an email appearing to be from their bank asking them to click a link and verify their account. This is MOST likely:",options:["Smishing","Whaling","Phishing","Vishing"],answer:2,explanation:"A deceptive email impersonating a trusted entity to steal credentials is a phishing attack.",optionExplanations:["Smishing uses SMS text messages to deliver the deceptive message.","Whaling targets high-profile executives specifically; this example is generic, so phishing is more accurate.","Phishing uses deceptive emails impersonating trusted entities to steal credentials or install malware.","Vishing uses phone calls (voice phishing) to trick victims, not emails."]},
  {id:80,domain:T,question:"What is ransomware?",options:["Software that silently captures every keystroke to harvest credentials and other sensitive user input","Malware that encrypts files and demands payment for decryption","Self-replicating malware that spreads automatically between systems via removable media or network file shares","Malware that embeds itself at the kernel or OS level to conceal attacker activity and maintain persistent privileged access"],answer:1,explanation:"Ransomware encrypts victim data and demands a ransom (often cryptocurrency) in exchange for the decryption key.",optionExplanations:["Software that silently captures keystrokes describes a keylogger or spyware, focused on credential theft rather than extortion.","Ransomware encrypts files or entire systems and extorts the victim for the decryption key.","Self-replicating malware spreading via removable media describes a worm; ransomware focuses on encryption and extortion.","Malware embedding itself at the kernel level to hide attacker access describes a rootkit, not ransomware."]},
  {id:81,domain:T,question:"Which social engineering technique involves an attacker pretending to be an IT support technician to gain access?",options:["Phishing","Pretexting","Tailgating","Baiting"],answer:1,explanation:"Pretexting creates a fabricated scenario (a pretext) to manipulate a target into revealing information or granting access.",optionExplanations:["Phishing is conducted via deceptive emails, not by impersonating a person in direct interaction.","Pretexting involves creating a false identity or scenario to manipulate someone into granting access.","Tailgating is physically following an authorized person through a secure entry point.","Baiting uses physical media (USB drives) or enticing offers to lure victims into taking dangerous actions."]},
  {id:82,domain:T,question:"What is a SQL injection attack?",options:["Overwhelming a database server with high volumes of connection requests until it exhausts available resources","Appending malicious bytecode to legitimate executable files so they execute attacker-controlled code when opened","Injecting malicious SQL code into an input field to manipulate a database","Intercepting and reading database query packets on the wire using a network protocol analyzer"],answer:2,explanation:"SQL injection inserts malicious SQL statements into unvalidated input fields to manipulate or extract database data.",optionExplanations:["Overwhelming a server with connection requests describes a denial-of-service attack targeting availability, not database manipulation.","Appending malicious code to executables describes a file-infecting virus, a different class of malware from SQL injection.","SQL injection exploits insufficient input validation to execute arbitrary SQL commands against the database.","Intercepting database packets on the network describes a man-in-the-middle attack, not a SQL injection technique."]},
  {id:83,domain:T,question:"Which of the following is a characteristic of an Advanced Persistent Threat (APT)?",options:["A campaign that focuses exclusively on compromising consumer mobile devices and personal social media accounts","An attack that relies entirely on phishing emails without employing any other technical exploitation techniques","It is a long-term, stealthy intrusion typically by a nation-state actor","An opportunistic, single-attempt attack using publicly available exploit tools and no specific target selection criteria"],answer:2,explanation:"APTs are prolonged, targeted attacks, often state-sponsored, focused on espionage or sabotage with minimal noise.",optionExplanations:["APTs target governments, critical infrastructure, defense contractors, and large enterprises, not primarily consumer devices or social media.","APTs use a wide range of techniques including zero-days, spear phishing, supply chain compromise, lateral movement, and custom malware.","APTs involve prolonged, stealthy access typically attributed to nation-states or well-funded groups with specific strategic objectives.","APTs are persistent and highly targeted; opportunistic single-attempt attacks using public tools describe commodity threat actors, not APTs."]},
  {id:84,domain:T,question:"What is the purpose of a botnet?",options:["Archive exfiltrated data records in cloud storage buckets that the attacker maintains under false identities","Apply TLS encryption to all outbound command-and-control traffic so network defenders cannot inspect its contents","Provide encrypted tunnels that allow legitimate corporate employees to securely access internal resources from remote locations","Coordinate large-scale attacks using infected systems controlled by an attacker"],answer:3,explanation:"A botnet is a network of compromised computers (bots) controlled by a command-and-control server for attacks.",optionExplanations:["While stolen data may be exfiltrated to cloud storage, a botnet is primarily an attack launch platform, not a data archiving service.","Botnets use C2 communications which may or may not be encrypted; applying TLS to all C2 traffic is one evasion technique, not the botnet's purpose.","Providing encrypted tunnels for employees to access internal resources remotely describes a VPN, not a botnet.","A botnet gives attackers a distributed platform of infected machines to launch DDoS attacks, spam campaigns, credential stuffing, and more."]},
  {id:85,domain:T,question:"Which attack type exploits unvalidated user input to execute scripts in a victim's browser?",options:["Buffer overflow","CSRF","SQL injection","Cross-site scripting (XSS)"],answer:3,explanation:"XSS injects malicious scripts into web pages viewed by other users, executing in their browser context.",optionExplanations:["Buffer overflow corrupts memory to execute code on the server or client, not via browser script injection.","CSRF tricks a browser into making unauthorized requests on behalf of a logged-in user, not script injection.","SQL injection targets database queries via input fields, not browser script execution.","XSS injects malicious JavaScript into a trusted web page, which then executes in victims' browsers."]},
  {id:86,domain:T,question:"What does a keylogger do?",options:["Records keystrokes to capture credentials and sensitive data","Enforces access control policies that restrict which users or processes are permitted to receive keyboard input events","Applies end-to-end encryption to keyboard input before it reaches the operating system, protecting data from interception","Maintains a version history of keyboard device firmware changes and driver installations for audit purposes"],answer:0,explanation:"A keylogger captures every keystroke made by the user, allowing attackers to steal passwords and sensitive information.",optionExplanations:["Keyloggers silently capture and exfiltrate keystrokes, often used to steal credentials and financial information.","Enforcing access control over keyboard input describes input validation or HID security policies, not keylogger behavior.","Encrypting keyboard input before it reaches the OS would defeat a keylogger's purpose; real keyloggers capture plaintext keystrokes.","Logging firmware version history is a patch management and asset tracking activity, not what a keylogger does."]},
  {id:87,domain:T,question:"What is a watering hole attack?",options:["Covertly loading malicious code onto removable USB drives and leaving them in high-traffic areas to tempt employees","Exploiting vulnerabilities in industrial control systems managing a utility's water treatment or distribution infrastructure","Sending personalized deceptive emails crafted with target-specific information to trick employees into clicking malicious links","Compromising a website frequently visited by the intended targets"],answer:3,explanation:"A watering hole attack compromises a website the target group regularly visits, infecting them when they browse it.",optionExplanations:["Loading malware onto USB drives and leaving them in public areas describes a baiting attack, not a watering hole.","Exploiting ICS systems in water treatment infrastructure is critical infrastructure sabotage, not a watering hole cyberattack.","Sending personalized deceptive emails with target-specific information describes spear phishing, not a watering hole attack.","Watering hole attacks compromise legitimate websites visited by targets, injecting malware to infect visitors silently."]},
  {id:88,domain:T,question:"What is the primary goal of a DDoS (Distributed Denial of Service) attack?",options:["Establish a persistent covert foothold in a target network for long-term espionage or data collection","Make a service unavailable by overwhelming it with traffic","Exfiltrate sensitive records from a target database by exploiting unvalidated input fields in web-facing applications","Encrypt victim files using asymmetric cryptography and demand cryptocurrency payment for the decryption key"],answer:1,explanation:"DDoS attacks flood a target with traffic from many sources to exhaust resources and deny service to legitimate users.",optionExplanations:["Establishing a persistent covert foothold describes an Advanced Persistent Threat; the goal is espionage, not denial of service.","DDoS attacks overwhelm a target with traffic from botnets, making the service unavailable to legitimate users.","Exfiltrating records through database exploits is a data theft attack focused on confidentiality, not disrupting availability.","Encrypting files for cryptocurrency ransom describes ransomware, which targets data integrity and extorts victims."]},
  {id:89,domain:T,question:"Which of the following BEST describes spear phishing?",options:["Fraudulent text messages containing malicious links or urgent prompts sent directly to a victim's mobile device","Highly targeted phishing attacks tailored to a specific individual or organization","Bulk deceptive emails sent simultaneously to millions of recipients using generic templates that impersonate banks or delivery services","Deceptive social engineering calls in which an attacker impersonates IT support or a financial institution over the phone"],answer:1,explanation:"Spear phishing uses personalized information about the target to make the deceptive message more convincing.",optionExplanations:["Fraudulent text messages with malicious links describe smishing (SMS phishing).","Spear phishing tailors the attack using the target's name, role, or relationships to increase believability.","Bulk deceptive emails sent to millions using generic templates describe standard (mass) phishing, not the personalized targeting of spear phishing.","Deceptive phone calls impersonating IT support or financial institutions describe vishing (voice phishing)."]},
  {id:90,domain:T,question:"What is a zero-day exploit?",options:["A high-volume traffic flood attack that overwhelms server resources and denies service to legitimate users","An exploit targeting an unknown vulnerability for which no patch exists","An exploit that is deployed on the same calendar day a software product is publicly released to market","An exploit whose source code is publicly released on the day the vulnerability is disclosed to the vendor"],answer:1,explanation:"A zero-day exploit attacks a vulnerability unknown to the vendor — there are zero days of warning or patching time.",optionExplanations:["A high-volume traffic flood describes a denial-of-service attack; zero-days are code exploits targeting software vulnerabilities.","A zero-day exploit targets a vulnerability the vendor is unaware of, meaning no patch exists at time of attack.","Timing relative to a software release date does not define a zero-day; the defining factor is that the vulnerability is unknown to the vendor.","Public release of exploit code on disclosure day describes a published proof-of-concept, not the definition of a zero-day (which is pre-disclosure)."]},
  {id:91,domain:T,question:"Which of the following BEST describes a man-in-the-browser attack?",options:["A fraudulent phishing page designed to closely mimic a legitimate bank's website","An attacker physically positions themselves between two users to intercept their communications","Malware intercepts and modifies browser transactions in real time","An attacker covertly monitors and logs a victim's browsing history over time"],answer:2,explanation:"Man-in-the-browser malware modifies web transactions inside the browser after authentication, often targeting banking.",optionExplanations:["A fake login page describes credential-harvesting phishing; MITB instead manipulates an already-authenticated legitimate session.","Physical positioning between two parties describes a traditional man-in-the-middle attack; man-in-the-browser is malware-based, not physical.","MITB malware hooks browser functions to alter transactions transparently to the user, bypassing TLS.","Passively logging browsing history describes spyware behavior, not the active transaction tampering of man-in-the-browser malware."]},
  {id:92,domain:T,question:"What is credential stuffing?",options:["Deliberately creating predictable or simplistic passwords that fail to meet minimum entropy requirements for complexity","Using large sets of stolen username/password pairs to attempt logins on multiple sites","Systematically attempting every possible character combination against a single target account until access is granted","Embedding malicious SQL syntax into web form credential fields to bypass authentication mechanisms"],answer:1,explanation:"Credential stuffing reuses breached credential lists against many sites, exploiting password reuse.",optionExplanations:["Deliberately creating weak passwords is poor password hygiene; credential stuffing attacks valid but reused credentials from breached databases.","Credential stuffing automates login attempts using leaked credential databases, exploiting password reuse across sites.","Systematically trying every character combination against one account describes a brute force attack, not credential stuffing.","Embedding SQL syntax into credential fields to bypass authentication describes SQL injection, not credential stuffing."]},
  {id:93,domain:T,question:"Which type of threat actor is MOST motivated by financial gain?",options:["Script kiddie","Cybercriminal","Hacktivist","Nation-state actor"],answer:1,explanation:"Cybercriminals are primarily motivated by financial gain through ransomware, fraud, or data theft.",optionExplanations:["Script kiddies use pre-made tools for notoriety or thrill, rarely with a clear financial agenda.","Cybercriminals seek financial profit through ransomware, banking trojans, and selling stolen data.","Hacktivists are motivated by ideology or political/social causes, not primarily financial gain.","Nation-state actors are motivated by espionage, disruption, or geopolitical objectives."]},
  {id:94,domain:T,question:"What is a buffer overflow attack?",options:["Embedding malicious JavaScript into a trusted web page so it executes in other users' browsers","Positioning an attacker between a client and server to intercept and modify data flowing between them","Writing more data to a buffer than it can hold to overwrite adjacent memory","Sending large volumes of UDP datagrams to a target server to exhaust its network bandwidth and processing capacity"],answer:2,explanation:"Buffer overflows occur when a program writes beyond allocated memory, potentially allowing code execution.",optionExplanations:["Embedding malicious JavaScript that executes in other users' browsers describes cross-site scripting (XSS).","Positioning between a client and server to intercept traffic describes a man-in-the-middle attack.","A buffer overflow writes data beyond the end of a fixed-size buffer, corrupting adjacent memory and potentially executing attacker code.","Sending high-volume UDP packets to exhaust bandwidth describes a UDP flood denial-of-service attack, not a memory exploit."]},
  {id:95,domain:T,question:"Which of the following is an indicator of a phishing email? (Choose the BEST answer)",options:["The email includes a properly formatted company signature block at the bottom","The email is digitally signed and encrypted using the organization's S/MIME certificate infrastructure","The email contains urgent language and requests credentials via a link","The email appears to come from a colleague the recipient already knows and trusts"],answer:2,explanation:"Urgency and requests to click links and provide credentials are classic phishing red flags.",optionExplanations:["A formatted company signature can be easily copied or spoofed, so its presence alone does not confirm legitimacy.","S/MIME encrypted and signed emails are unusual for phishing but not impossible, and legitimate emails are also often signed.","Urgency, requests for credentials, and embedded links are the most reliable phishing indicators.","Emails appearing to come from known colleagues can still be legitimate, though spear phishing frequently spoofs trusted senders."]},
  {id:96,domain:T,question:"What is a logic bomb?",options:["Covert malware that continuously records screen contents and user activity and transmits them to a remote attacker","Malicious code that executes when a specific condition or trigger is met","Software that floods a target with excessive traffic to exhaust available network bandwidth and processing resources","Self-replicating malware that propagates rapidly across a network by exploiting open shares and unpatched vulnerabilities"],answer:1,explanation:"A logic bomb lies dormant until a specific trigger (date, event, action) activates the malicious payload.",optionExplanations:["Covert malware recording screen activity and transmitting it describes spyware or a RAT, not a logic bomb.","A logic bomb remains dormant until a defined trigger (e.g., a date or the absence of an employee's login) fires the payload.","Software flooding a target to exhaust resources describes a denial-of-service tool; logic bombs execute local payloads.","Self-replicating malware spreading through network shares and vulnerabilities describes a worm, not a logic bomb."]},
  {id:97,domain:T,question:"What type of malware conceals itself and steals data over an extended period without detection?",options:["Spyware","Worm","Ransomware","Virus"],answer:0,explanation:"Spyware covertly monitors user activity and exfiltrates data without the user's knowledge.",optionExplanations:["Spyware silently monitors and transmits user activity, browsing, and credentials to attackers.","Worms self-replicate and spread; their main goal is propagation rather than stealth data collection.","Ransomware makes itself known by displaying a ransom demand after encryption.","Viruses attach to files and replicate when files execute; they are not primarily designed for stealth data collection."]},
  {id:98,domain:T,question:"Which of the following describes a vishing attack?",options:["A phishing attack conducted over the phone","A phishing attack delivered via email","A phishing attack using SMS messages","A phishing attack through social media"],answer:0,explanation:"Vishing (voice phishing) uses telephone calls to manipulate victims into revealing sensitive information.",optionExplanations:["Vishing uses phone calls (voice) to impersonate banks, IT support, or government agencies to steal information.","Email phishing is simply called phishing.","SMS-based phishing is smishing (SMS phishing).","Social media phishing can be considered spear phishing or social engineering but is not vishing."]},
  {id:99,domain:T,question:"What is the purpose of a threat intelligence feed?",options:["Provision user accounts with appropriate access rights and manage entitlements throughout the identity lifecycle","Apply cryptographic algorithms to protect sensitive data from unauthorized disclosure during storage and transmission","Provide real-time or near-real-time information about known threats, indicators, and TTPs","Scan endpoints in real time for known malware signatures and quarantine malicious files before they can execute"],answer:2,explanation:"Threat intelligence feeds provide up-to-date data on threats, attacker TTPs, malware hashes, malicious IPs, and IOCs.",optionExplanations:["Provisioning and managing user account entitlements describes identity and access management (IAM) solutions.","Applying cryptographic algorithms to protect sensitive data describes encryption tools and protocols.","Threat intelligence feeds supply actionable information (IOCs, TTPs, threat actor profiles) to improve detection and response.","Scanning endpoints for malware signatures and quarantining threats is the function of EDR and antivirus software."]},
  {id:100,domain:T,question:"Which of the following BEST describes a supply chain attack?",options:["Compromising a vendor or software provider to inject malware into their product before delivery","Exfiltrating sensitive records from a cloud provider's databases by exploiting misconfigured storage permissions","Gaining unauthorized physical entry to a vendor's warehouse or shipping facility to tamper with hardware during transit","Sending targeted phishing emails to employees of a supplier organization to harvest their login credentials"],answer:0,explanation:"Supply chain attacks compromise trusted third-party software or hardware before it reaches the target organization.",optionExplanations:["Supply chain attacks compromise upstream vendors, inserting malicious code into updates or hardware before delivery.","Exfiltrating data from a cloud provider through misconfigured storage is a cloud breach, not a supply chain attack exploiting the trusted vendor relationship.","Unauthorized physical access to a warehouse to tamper with hardware is sabotage; supply chain attacks typically involve software compromise at the vendor level.","Phishing supplier employees to harvest credentials may be a preliminary step, but it is not the defining characteristic of a supply chain attack."]},
  {id:101,domain:T,question:"What is typosquatting?",options:["Inserting malicious scripts or backdoors directly into the source code of a legitimate website","Injecting forged DNS responses into a resolver's cache to redirect traffic to attacker-controlled IP addresses","Stealing authenticated browser session tokens to impersonate a logged-in user without knowing their credentials","Registering domains with common misspellings of legitimate sites to deceive users"],answer:3,explanation:"Typosquatting registers domains like 'googlle.com' hoping users mistype a URL and land on the malicious site.",optionExplanations:["Inserting malicious scripts directly into a legitimate website's code describes a web application compromise or watering hole attack.","Injecting forged DNS responses to redirect traffic describes DNS cache poisoning or spoofing, not typosquatting.","Stealing authenticated session tokens to impersonate a logged-in user describes session hijacking, not typosquatting.","Typosquatting exploits common typographical mistakes to register deceptive domain names that mimic legitimate ones."]},
  {id:102,domain:T,question:"Which term describes when an attacker pretends to be an executive in an email to trick employees into transferring funds?",options:["Whaling that targets senior executives themselves as the phishing victims","Business email compromise (BEC) impersonating an executive to authorize fraud","Spear phishing that targets a specific, carefully researched individual employee","Smishing that delivers fraudulent text messages to a victim's phone"],answer:1,explanation:"BEC (Business Email Compromise) specifically targets organizations by impersonating executives to authorize fraudulent transfers.",optionExplanations:["Whaling is phishing that targets executives as the victims, not impersonating them to attack others.","BEC impersonates executives or vendors by email to manipulate employees into making unauthorized financial transfers.","Spear phishing is a personalized attack on a specific target; BEC is a subset that specifically targets financial fraud via executive impersonation.","Smishing relies on SMS text messages; BEC is specifically an email-based financial fraud scheme."]},
  {id:103,domain:T,question:"What is an indicator of compromise (IoC)?",options:["A documented list of pre-approved firewall rules governing allowed network traffic","A report generated by an automated tool listing discovered system vulnerabilities","A specific category or family of malicious software designed to cause harm","Evidence suggesting a system has been breached or is under attack"],answer:3,explanation:"IoCs are artifacts like suspicious IPs, malware hashes, or unusual log entries that indicate a possible compromise.",optionExplanations:["Approved firewall rules are security configuration items used to permit or deny traffic, not compromise indicators.","Vulnerability scan results describe potential weaknesses in a system; IoCs indicate an attack that has actually occurred.","Malware is the threat itself; IoCs are the evidence artifacts left behind by malware or attacker activity.","IoCs are forensic artifacts — IP addresses, file hashes, domain names, or behavioral patterns — indicating compromise."]},
  {id:104,domain:T,question:"What is shimming in the context of malware?",options:["A software compatibility shim technique that replaces deprecated API calls with updated equivalents for newer operating systems","A network bridging technique that connects two separate Layer 2 network segments by forwarding frames between physical interfaces","Malware that inserts itself between a legitimate application and its dependencies to intercept calls","A steganography technique that conceals secret data within digital image files by manipulating least-significant bits of pixel values"],answer:2,explanation:"Shimming malware inserts a malicious layer between an application and the OS/API to intercept function calls.",optionExplanations:["This describes a legitimate software compatibility layer, not malware; shimming as malware specifically intercepts calls to steal data or inject code.","Bridging connects network segments at Layer 2 and is a networking concept unrelated to malware shimming.","Shimming inserts malicious code as a compatibility layer to intercept API calls between applications and system libraries.","Steganography hides data inside media files; shimming malware instead inserts itself as an intermediary to intercept API calls."]},
  {id:105,domain:T,question:"Which of the following BEST describes a fileless malware attack?",options:["Malware that automatically deletes its own executable file immediately after it finishes running","Malware whose malicious code is concealed inside the pixel data of ordinary image files","Malware that runs entirely in memory without writing files to disk","Malware that conceals its executable files within hidden or disguised folders on the disk"],answer:2,explanation:"Fileless malware operates in RAM using legitimate system tools (e.g., PowerShell), leaving no files on disk.",optionExplanations:["Self-deleting malware still touches the disk before removing itself; fileless malware never writes files to disk in the first place.","Concealing code inside images describes steganography-based malware delivery; fileless malware avoids the disk entirely rather than hiding within a file type.","Fileless malware runs in memory leveraging tools like PowerShell or WMI, evading file-based antivirus detection.","Hiding files on disk is traditional stealth malware behavior; fileless malware specifically avoids writing any files to disk at all."]},
  {id:106,domain:T,question:"What is a rainbow table attack?",options:["Systematically testing character combinations against wireless network authentication to recover the WPA2 pre-shared key","Capturing hashed authentication credentials as they traverse the network using a packet capture tool","Submitting randomly generated password attempts against a live login form at high speed to gain unauthorized access","Using precomputed hash values to reverse password hashes faster than brute force"],answer:3,explanation:"Rainbow tables are precomputed lists of plaintext-to-hash mappings, used to quickly reverse unsalted password hashes.",optionExplanations:["Systematically testing character combinations against wireless authentication describes a WPA2 brute force attack, not a rainbow table attack.","Capturing hashed credentials on the wire is a network sniffing attack; rainbow tables are used offline after capturing hashes.","Submitting randomly generated passwords against a live login form is an online brute force attack.","Rainbow tables use precomputed hash chains to find the plaintext behind a hash without recomputing each guess."]},
  {id:107,domain:T,question:"Which type of attack sends unsolicited Bluetooth messages to nearby devices?",options:["Bluejacking","Bluesnarfing","Bluebugging","Evil twin"],answer:0,explanation:"Bluejacking sends unsolicited messages (like contact cards) to nearby Bluetooth-enabled devices.",optionExplanations:["Bluejacking sends unsolicited messages to nearby Bluetooth devices — generally annoying but not data-stealing.","Bluesnarfing illegally accesses and downloads data from a Bluetooth device without permission.","Bluebugging takes full control of a Bluetooth device, including calls and messages — more severe than bluejacking.","Evil twin is a rogue Wi-Fi AP attack, not a Bluetooth attack."]},
  {id:108,domain:T,question:"What is a cross-site request forgery (CSRF) attack?",options:["Injecting malicious scripts into web pages viewed by other users","Injecting malicious SQL statements into database queries by submitting unsanitized input through web application form fields","Tricking a user's browser into making unauthorized requests to a site where they are authenticated","Capturing authentication tokens from network traffic by using ARP spoofing to redirect sessions through an attacker-controlled host"],answer:2,explanation:"CSRF tricks an authenticated user's browser into making unwanted requests to a trusted site, leveraging existing session tokens.",optionExplanations:["Injecting malicious scripts is XSS, not CSRF.","This describes SQL injection, not CSRF; CSRF exploits a user's authenticated browser session rather than manipulating database queries.","CSRF forces an authenticated user's browser to perform actions on a site they're logged into without their knowledge.","This describes session hijacking via ARP spoofing, not CSRF; CSRF abuses existing authenticated sessions rather than stealing tokens from the network."]},
  {id:109,domain:T,question:"What does 'pivoting' mean in a penetration test?",options:["Deleting event logs, removing attacker tools, and clearing shell history to prevent forensic reconstruction of post-exploitation activity","Switching an attacker's methodology from external perimeter reconnaissance to exploiting services on the internal corporate network","Exploiting local kernel vulnerabilities or misconfigured SUID binaries to elevate from a standard user to root on a single host","Using a compromised host as a launching point to attack other systems on the network"],answer:3,explanation:"Pivoting uses a compromised system as a relay to reach and attack otherwise inaccessible network segments.",optionExplanations:["This describes anti-forensics and covering tracks, a separate post-exploitation phase; pivoting is about reaching new network targets, not concealing activity.","Changing attack methodology describes a general strategy shift, not specifically pivoting; pivoting requires using a compromised host as the transit point.","This describes privilege escalation on one system, a separate step; pivoting moves laterally to other systems using an already-compromised host as a launchpad.","Pivoting leverages a compromised host to tunnel traffic and reach internal hosts not directly accessible from the internet."]},
  {id:110,domain:T,question:"Which of the following BEST describes a man-in-the-middle (MITM) attack prevention?",options:["Enabling two-factor authentication only","Updating firewall rules","Using complex passwords","Implementing certificate pinning and mutual TLS"],answer:3,explanation:"Certificate pinning and mutual TLS ensure both parties verify each other's certificates, preventing MITM interception.",optionExplanations:["2FA verifies identity at login but does not prevent in-transit communication interception.","Firewall rules control network traffic flow but do not prevent MITM attacks within allowed traffic streams.","Complex passwords protect against credential attacks but not MITM interception of traffic.","Certificate pinning and mutual TLS prevent MITM by requiring both client and server to authenticate certificates."]},
  {id:111,domain:T,question:"Which of the following is a passive reconnaissance technique?",options:["Attempting to log in with default credentials","Researching a company's public website and social media","Port scanning the target","Sending phishing emails"],answer:1,explanation:"Passive reconnaissance gathers information without directly interacting with target systems (OSINT, public records).",optionExplanations:["Attempting logins is active and may trigger alarms.","Reviewing public websites and social media is OSINT — passive, with no direct interaction with target systems.","Port scanning directly probes target systems, making it active reconnaissance.","Phishing is an active attack, not reconnaissance."]},
  {id:112,domain:T,question:"What is the purpose of a honeypot?",options:["Provide encrypted communication tunnels for remote users connecting to the corporate network","Lure attackers to a decoy system to observe and analyze their techniques","Inspect inbound and outbound network packets and automatically block sessions matching malicious threat signatures","Maintain redundant copies of production data in an isolated repository protected against accidental deletion or corruption"],answer:1,explanation:"Honeypots are intentionally vulnerable decoy systems designed to attract attackers and study their behavior.",optionExplanations:["Providing encrypted tunnels for remote users describes a VPN solution, not a honeypot.","A honeypot is a decoy resource designed to detect, distract, and study attackers without risk to real systems.","Inspecting packets and blocking malicious sessions describes an intrusion prevention system, not a honeypot.","Maintaining redundant data copies describes a backup repository; honeypots are decoy systems, not storage resources."]},
  {id:113,domain:T,question:"An attacker intercepts encrypted HTTPS traffic for later decryption. What type of attack is this?",options:["SSL stripping","Capture now, decrypt later","Pass-the-hash","Replay attack"],answer:1,explanation:"'Harvest now, decrypt later' (capture now, decrypt later) saves encrypted traffic hoping to decrypt it when keys are available or quantum computing matures.",optionExplanations:["SSL stripping downgrades HTTPS to HTTP in real time; it doesn't capture for later decryption.","'Capture now, decrypt later' stockpiles encrypted data to decrypt once decryption capability becomes available.","Pass-the-hash steals NTLM hashes for authentication without knowing the plaintext.","A replay attack resends captured credentials or tokens; it does not store encrypted traffic for future decryption."]},
  {id:114,domain:T,question:"What is tailgating in physical security?",options:["Planting an infected USB drive in a parking lot hoping an employee plugs it in","Following an authorized person through a secure door without authentication","Covertly monitoring an employee's computer activity from a remote location without their knowledge","Sending a fraudulent email that impersonates a trusted colleague to manipulate the recipient"],answer:1,explanation:"Tailgating (piggybacking) bypasses physical access controls by following an authorized person through a secured entry.",optionExplanations:["Planting a USB drive to lure someone into plugging it in describes a baiting attack, not tailgating.","Tailgating exploits social courtesy to physically bypass access controls without badging in.","Remotely monitoring a computer is a cyber surveillance technique, not a physical tailgating attack.","Impersonating a colleague by email describes phishing or business email compromise, not a physical security bypass."]},
  {id:115,domain:T,question:"Which of the following BEST describes a logic bomb?",options:["Malware that encrypts victim files using a symmetric key and demands cryptocurrency ransom for the decryption key","Code that executes a malicious payload when a specific condition is met","Self-replicating malware that propagates between Bluetooth-enabled devices without requiring user interaction","A destructive virus that immediately overwrites or deletes files on the host system upon execution"],answer:1,explanation:"Logic bombs trigger on conditions like a date, time, or event — e.g., deleting files if an employee account is disabled.",optionExplanations:["Malware encrypting files for cryptocurrency ransom describes ransomware; a logic bomb's defining trait is conditional execution, not encryption.","A logic bomb stays dormant until a specific trigger condition is met before executing its payload.","Malware spreading autonomously between Bluetooth-enabled devices describes a Bluetooth worm, not a logic bomb.","A virus that immediately destroys files upon execution is a wiper; logic bombs delay their action until a trigger event."]},
  {id:116,domain:T,question:"An employee copies sensitive company data to a personal USB drive before leaving. What type of threat is this?",options:["Insider threat","Zero-day attack","Supply chain attack","External threat"],answer:0,explanation:"Malicious or negligent behavior by an internal employee or contractor constitutes an insider threat.",optionExplanations:["An insider threat involves an employee, contractor, or trusted person who misuses their access.","Zero-day attacks exploit unknown vulnerabilities in software; this is data theft by an insider.","Supply chain attacks compromise vendors or products before delivery; this is internal data theft.","External threats originate outside the organization; this employee is an insider."]},
  {id:117,domain:T,question:"What is a pharming attack?",options:["Redirecting users from legitimate websites to malicious ones via DNS manipulation","Distributing large volumes of deceptive emails impersonating trusted brands to trick recipients into revealing credentials","Creating a rogue wireless access point with the same SSID as a legitimate network to intercept user traffic","Embedding malicious code in email attachments that executes when the recipient opens the file or enables macros"],answer:0,explanation:"Pharming corrupts DNS settings or poisons caches to redirect users to malicious sites even when they type the correct URL.",optionExplanations:["Pharming redirects traffic at the DNS level, so even correct URLs resolve to attacker-controlled sites.","Distributing deceptive emails impersonating trusted brands describes mass phishing, not pharming.","Creating a rogue AP with the same SSID as a legitimate network describes an evil twin attack.","Embedding malicious code in email attachments that executes when opened describes email-based malware delivery."]},
  {id:118,domain:T,question:"Which of the following is an example of a brute force attack?",options:["Trying every possible password combination until one works","Manipulating a help desk employee into resetting an account password by fabricating a plausible identity","Stealing an authenticated browser session cookie from network traffic to impersonate a logged-in user","Inserting malicious SQL syntax into a web application's login field to bypass authentication database queries"],answer:0,explanation:"A brute force attack systematically tries all possible combinations of characters until the correct password is found.",optionExplanations:["Brute force exhaustively tries every possible password combination until finding the correct one.","Manipulating a help desk employee to reset an account describes social engineering.","Stealing an authenticated session cookie from traffic to impersonate a user describes session hijacking.","Inserting malicious SQL into a login field to bypass authentication describes SQL injection, not brute force."]},
  {id:119,domain:T,question:"What distinguishes a worm from a virus?",options:["Worms must attach to an executable host file to spread; viruses propagate autonomously across network connections without a host","Worms self-replicate and spread independently; viruses need to attach to a host file","Viruses spread automatically over networks; worms require user interaction","Worms require a host file to spread; viruses do not"],answer:1,explanation:"Worms are self-contained and self-propagating; viruses require a host file and user action to spread.",optionExplanations:["This reverses the definitions; worms spread autonomously without a host file, while viruses require a host file to attach to and propagate.","A worm self-replicates and propagates across networks without user interaction or a host file.","Viruses require user action (opening an infected file); worms spread autonomously.","It is viruses that require a host file; worms are self-contained."]},
  {id:120,domain:T,question:"Which attack technique uses multiple systems to overwhelm a target?",options:["APT","Spear phishing","DDoS","MITM"],answer:2,explanation:"DDoS (Distributed Denial of Service) uses botnets of many systems to flood a target with traffic.",optionExplanations:["APTs are prolonged stealthy intrusions; they don't necessarily use volume-based flooding.","Spear phishing is a targeted social engineering email attack, not a multi-system flooding attack.","DDoS distributes the attack across many compromised systems to amplify the flood against a single target.","MITM intercepts communication between two parties; it doesn't require many attacking systems."]},
  {id:121,domain:T,question:"What does OSINT stand for and what is its primary use in security?",options:["Online Security Intelligence — a practice limited to monitoring dark web criminal forums","Operational Security Intelligence — a discipline focused on protecting classified operational data","Open Source Intelligence — gathering information from public sources for reconnaissance","On-Site Intelligence — a discipline focused exclusively on physical penetration testing engagements"],answer:2,explanation:"OSINT collects intelligence from publicly available sources (social media, websites, job postings) for reconnaissance.",optionExplanations:["OSINT can include monitoring the dark web, but it is not limited to online sources, and this is not what the acronym stands for.","Operational Security (OPSEC) is about protecting sensitive operational information, which is the opposite of OSINT's information-gathering purpose.","OSINT (Open Source Intelligence) uses publicly available data to learn about targets before attacking.","On-Site Intelligence is not a recognized security term; OSINT does not stand for this and is not limited to physical testing."]},
  {id:122,domain:T,question:"Which of the following is a characteristic of spyware?",options:["Repeatedly displays intrusive, unwanted advertisements to the user without their consent","Encrypts a victim's files and demands payment in exchange for the decryption key","Covertly monitors user activity and transmits data to a third party","Automatically replicates itself across network shares to infect additional connected systems"],answer:2,explanation:"Spyware secretly observes user behavior, keystroke logging, browsing, and transmits data to the attacker.",optionExplanations:["Displaying unwanted ads describes adware, which is a distinct category from covert data-collecting spyware.","Encrypting files and demanding payment describes ransomware, not spyware.","Spyware covertly collects and exfiltrates user information such as credentials, browsing history, and personal data.","Self-replication across a network describes worm behavior, not spyware's covert monitoring function."]},
  {id:123,domain:T,question:"A SCADA system at a power plant is attacked, causing physical damage to turbines. Which type of attack is this?",options:["Ransomware attack","Cyber-physical attack","DDoS attack","Phishing attack"],answer:1,explanation:"Cyber-physical attacks target industrial control systems (ICS/SCADA) to cause physical harm to equipment or infrastructure.",optionExplanations:["Ransomware encrypts data for extortion; it does not typically cause physical equipment damage.","A cyber-physical attack uses cyber means to cause real-world physical consequences, as seen in Stuxnet.","DDoS disrupts availability of services; it does not directly cause physical equipment damage.","Phishing is a social engineering technique to steal credentials, not to damage physical equipment."]},
  {id:124,domain:T,question:"What is the difference between a vulnerability and an exploit?",options:["An exploit is a weakness; a vulnerability is the attack tool","A vulnerability is the attack tool leveraged to compromise systems; an exploit is the underlying weakness discovered by security scanners","A vulnerability is a weakness; an exploit is the code or technique that takes advantage of it","A vulnerability and an exploit are interchangeable security terms both describing the same exploitable flaw within a target system"],answer:2,explanation:"A vulnerability is the flaw (weakness); an exploit is the method or code that leverages that flaw to attack.",optionExplanations:["An exploit uses the vulnerability, not the other way around.","This reverses the definitions; a vulnerability is the weakness, and an exploit is the technique that leverages the vulnerability to cause harm.","A vulnerability is the underlying weakness in software or configuration; an exploit weaponizes that weakness.","They are not the same; a vulnerability is a weakness that exists, while an exploit is the specific code or method used to take advantage of it."]},
  {id:125,domain:T,question:"Which threat vector uses text messages to deliver phishing attacks?",options:["Vishing","Smishing","Whaling","Phishing"],answer:1,explanation:"Smishing = SMS phishing — malicious links or prompts sent via text message.",optionExplanations:["Vishing uses voice calls (phone) for phishing.","Smishing specifically uses SMS text messages to deliver phishing content.","Whaling targets executives as the victims, regardless of delivery channel.","Phishing is the general email-based version."]},
  {id:126,domain:A,question:"What is the purpose of a DMZ in network security?",options:["Encrypt traffic exchanged directly between internal users on the corporate network","Host publicly accessible services while isolating the internal network","Store backup copies of organizational data for disaster recovery purposes","Provide wireless network access to employees throughout the office building"],answer:1,explanation:"A DMZ (Demilitarized Zone) places public-facing servers between two firewalls, protecting the internal network.",optionExplanations:["Traffic encryption between internal users is provided by VPNs and TLS, not by a DMZ architecture.","A DMZ isolates public-facing services (web, email, DNS) from the internal corporate network using firewall layers.","Backup data is stored in dedicated backup repositories, not in a DMZ.","Wireless access is provided by access points and controllers, not by a DMZ."]},
];
